@app.get("/reset-mfa/confirm")
def reset_mfa_confirm():
    raw_token = request.args.get("token", "").strip()
    if not raw_token:
        return jsonify({"error": "missing_token"}), 400

    token_h = hash_token(raw_token)
    row = db().execute(
        "SELECT * FROM reset_tokens WHERE token_hash = ?",
        (token_h,),
    ).fetchone()

    if not row:
        return jsonify({"error": "invalid_or_expired_token"}), 400
    if row["used_at"] is not None:
        return jsonify({"error": "token_already_used"}), 400
    if row["expires_at"] < now_ts():
        return jsonify({"error": "invalid_or_expired_token"}), 400

    user = get_user_by_id(row["user_id"])
    if not user:
        return jsonify({"error": "invalid_or_expired_token"}), 400

    disable_mfa_for_user(user["id"])
    db().execute("UPDATE reset_tokens SET used_at = ? WHERE id = ?", (now_ts(), row["id"]))
    db().commit()

    return jsonify({"ok": True, "message": "MFA disabled. You can now log in with password only."})


